-- {"operators": "INNER_JOIN,AGGREGATE", "complexity": "medium", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "WAREHOUSE,DISTRICT,ORDER_LINE", "lakeflow": "group_by_all", "note": "Lakeflow GROUP BY ALL test: 3-way join with COUNT/SUM/AVG and GROUP BY ALL. MV creation and incremental refresh both work correctly."}
SELECT w.W_ID, d.D_ID, COUNT(ol.OL_O_ID) AS order_count, SUM(ol.OL_AMOUNT) AS total_amount, AVG(ol.OL_AMOUNT) AS avg_amount FROM WAREHOUSE w JOIN DISTRICT d ON w.W_ID = d.D_W_ID JOIN ORDER_LINE ol ON ol.OL_W_ID = d.D_W_ID AND ol.OL_D_ID = d.D_ID GROUP BY ALL
